), target_items as (
	select id, collection, title
	from public.culture_items
	where category = 'geography'
		and collection in ('country_capitals', 'us_state_capitals', 'french_department_numbers')
)
insert into public.culture_prompts (
	item_id,
	prompt_direction,
	prompt_type,
	question,
	answer,
	answer_aliases,
	choices,
	sort_order
)
select
	target_items.id,
	source_prompts.prompt_direction,
	source_prompts.prompt_type,
	source_prompts.question,
	source_prompts.answer,
	source_prompts.answer_aliases,
	source_prompts.choices,
	source_prompts.sort_order
from source_prompts
join target_items
	on target_items.collection = source_prompts.collection
	and target_items.title = source_prompts.item_title
where not exists (
	select 1
	from public.culture_prompts existing_prompts
	where existing_prompts.item_id = target_items.id
		and existing_prompts.prompt_direction = source_prompts.prompt_direction
		and existing_prompts.prompt_type = source_prompts.prompt_type
);

